	...

	adv7343@2a {
		compatible = "adi,adv7343";
		reg = <0x2a>;

		port {
			adv7343_1: endpoint {
					adi,power-mode-sleep-mode;
					adi,power-mode-pll-ctrl;
					/* Use DAC1..3, DAC6 */
					adi,dac-enable = <1 1 1 0 0 1>;
					/* Use SD DAC output 1 */
					adi,sd-dac-enable = <1 0>;
			};
		};
	};
	...
};

